/* InternshipDetails.jsx */
import React, { useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { internships } from '../data/mockData';
import InternshipCard from '../components/InternshipCard';

export default function InternshipDetails() {
  const { id } = useParams();
  const [saved, setSaved] = useState(false);

  const internship = internships.find(i => i.id === id);
  const similar = internships.filter(i => i.id !== id && i.category === internship?.category).slice(0, 2);

  if (!internship) {
    return (
      <div className="idetail__not-found page-enter">
        <h2>Internship not found</h2>
        <Link to="/internships" className="btn btn-primary">Browse All Internships</Link>
      </div>
    );
  }

  const { role, company, logo, logoColor, location, remote, stipend,
          duration, startDate, applyBy, tags, tagColor, description,
          about, skills, responsibilities, openings, applicants, category } = internship;

  return (
    <div className="idetail page-enter">
      {/* BANNER */}
      <div className="idetail__banner" style={{ '--accent': logoColor }}>
        <div className="idetail__banner-glow"></div>
        <div className="container idetail__banner-inner">
          <Link to="/internships" className="idetail__back">← All Internships</Link>
          <div className="idetail__banner-main">
            <div className="idetail__banner-logo" style={{ color: logoColor }}>{logo}</div>
            <div className="idetail__banner-info">
              <div className="idetail__category-tag">
                <span className={`tag tag-${tagColor}`}>{category}</span>
                {remote && <span className="tag tag-mint">🌐 Remote</span>}
              </div>
              <h1 className="idetail__role">{role}</h1>
              <div className="idetail__company-row">
                <span className="idetail__company">{company}</span>
                <span className="idetail__separator">·</span>
                <span className="idetail__location">📍 {remote ? 'Remote' : location}</span>
                <span className="idetail__separator">·</span>
                <span className="idetail__openings">{openings} Opening{openings > 1 ? 's' : ''}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* MAIN SPLIT LAYOUT */}
      <div className="container idetail__body">
        {/* LEFT — CONTENT (70%) */}
        <div className="idetail__content">

          {/* About */}
          <section className="idetail__section">
            <h3 className="idetail__section-title">About the Company</h3>
            <p>{about}</p>
          </section>

          <div className="divider"></div>

          {/* Description */}
          <section className="idetail__section">
            <h3 className="idetail__section-title">Role Description</h3>
            <p>{description} You'll be working in a high-ownership environment where your contributions
              directly shape the product. Expect real challenges, genuine mentorship, and a team that
              values craft and clarity.
            </p>
          </section>

          <div className="divider"></div>

          {/* Responsibilities */}
          <section className="idetail__section">
            <h3 className="idetail__section-title">Responsibilities</h3>
            <ul className="idetail__list">
              {responsibilities.map((r, i) => (
                <li key={i} className="idetail__list-item">
                  <span className="idetail__list-bullet">✦</span>
                  {r}
                </li>
              ))}
            </ul>
          </section>

          <div className="divider"></div>

          {/* Skills */}
          <section className="idetail__section">
            <h3 className="idetail__section-title">Skills Required</h3>
            <div className="idetail__skills">
              {skills.map(s => (
                <span key={s} className={`tag tag-${tagColor} idetail__skill-tag`}>{s}</span>
              ))}
            </div>
          </section>

          <div className="divider"></div>

          {/* Match Score Teaser */}
          <section className="idetail__match-teaser">
            <div className="idetail__match-lock">🔒</div>
            <div className="idetail__match-text">
              <h4>Your Profile Match Score</h4>
              <p>Login to see how well your skills align with this role and get a personalized compatibility score.</p>
            </div>
            <div className="idetail__match-score-preview">
              <div className="idetail__score-ring">
                <span className="idetail__score-ring-label">??%</span>
              </div>
            </div>
            <Link to="/login" className="btn btn-primary idetail__match-btn">Reveal Match Score</Link>
          </section>

          {/* Similar Internships */}
          {similar.length > 0 && (
            <>
              <div className="divider"></div>
              <section className="idetail__section">
                <h3 className="idetail__section-title">Similar Opportunities</h3>
                <div className="idetail__similar-grid">
                  {similar.map(i => <InternshipCard key={i.id} internship={i} variant="compact" />)}
                </div>
              </section>
            </>
          )}
        </div>

        {/* RIGHT — STICKY PANEL (30%) */}
        <aside className="idetail__sidebar">
          <div className="idetail__apply-panel">
            {/* Stats */}
            <div className="idetail__stats-grid">
              {[
                { icon: '💰', label: 'Stipend',    value: `₹${stipend.toLocaleString()}/mo` },
                { icon: '📅', label: 'Duration',   value: duration },
                { icon: '🗓️', label: 'Start Date', value: startDate },
                { icon: '⏰', label: 'Apply By',   value: applyBy },
                { icon: '👥', label: 'Openings',   value: `${openings} position${openings > 1 ? 's' : ''}` },
                { icon: '📈', label: 'Applicants', value: `${applicants}+` },
              ].map(stat => (
                <div key={stat.label} className="idetail__stat">
                  <span className="idetail__stat-icon">{stat.icon}</span>
                  <div>
                    <span className="idetail__stat-label">{stat.label}</span>
                    <span className="idetail__stat-value">{stat.value}</span>
                  </div>
                </div>
              ))}
            </div>

            <div className="divider" style={{ margin: '0' }}></div>

            {/* Tags */}
            <div className="idetail__panel-tags">
              {tags.map(t => <span key={t} className={`tag tag-${tagColor}`}>{t}</span>)}
            </div>

            {/* CTA */}
            <Link to="/login" className="btn btn-primary btn-lg idetail__apply-btn">
              Login to Apply
            </Link>
            <button
              className={`btn idetail__save-btn ${saved ? 'idetail__save-btn--saved' : 'btn-ghost'}`}
              onClick={() => setSaved(!saved)}>
              {saved ? '♥ Saved' : '♡ Save for Later'}
            </button>

            <p className="idetail__apply-note">
              🔐 Create a free account to track applications, save internships, and unlock AI match scores.
            </p>
          </div>

          {/* Quick Facts Card */}
          <div className="idetail__perks-card">
            <h5 className="idetail__perks-title">Why this role?</h5>
            {['Real ownership from day one', 'Mentorship from senior engineers', 'Certificate upon completion', 'PPO opportunity for top performers'].map(p => (
              <div key={p} className="idetail__perk">
                <span className="idetail__perk-dot">✓</span>
                <span>{p}</span>
              </div>
            ))}
          </div>
        </aside>
      </div>
    </div>
  );
}
